INSERT INTO "Event" VALUES ('cmntcefdl0000amhpqxmofany', 'Jack White - Live 2026', 'CONCERT', 'Jack White', '3Olympia Theatre', 'Dublin', 'IE', '2026-09-01 00:00:00', NULL, 'https://www.ticketmaster.ie/jack-white-live-2026-dublin-01-09-2026/event/18006488A864E33C', NULL, 'Under 14s must be accompanied by an adult. Standing tickets are recommended only for those over 16 years of age. PLEASE NOTE: THIS IS A PHONE-FREE SHOW. WHAT IS A "PHONE-FREE SHOW"? No phones allowed in the performance space. An unplugged, real life experience. HOW DOES IT WORK? Upon arrival at the venue, staff will be available to help you put your phone in a lockable pouch which you keep throughout the night. WHAT IF I HAVE AN EMERGENCY AND NEED TO ACCESS MY PHONE? You can unlock your phone from the pouch at any time by going to the clearly-marked Phone Use Areas located in the lobby or the concourse. WHAT ABOUT CASHLESS BARS OR MERCH? We highly recommend bringing a physical credit card just in case you can''t access your phone at the bar or merch area. WHY ARE YOU DOING THIS & IS IT MANDATORY? We believe this creates a better experience for everyone & yes, it''s non-negotiable.', 'https://s1.ticketm.net/dam/a/1cc/dbbdb302-9c0e-42cc-baaa-8cae6651c1cc_TABLET_LANDSCAPE_LARGE_16_9.jpg', 'Rock', 'TICKETMASTER', '1AbZk3FGkeI_CGH', 'tm-jack-white-3olympia-theatre-dublin-2026-09-01', 53.344318, -6.266114, true, '2026-04-10 20:12:31.449', '2026-04-10 21:43:20.06', NULL, NULL, NULL, '19:00:00', 'Pop', false, 'https://www.facebook.com/jackwhite', 'https://www.instagram.com/officialjackwhite/?hl=en', 'https://open.spotify.com/artist/4FZ3j1oH43e7cukCALsCwf?si=vOgHWuusQlOPrMXXLe-5Bw', NULL, NULL, 'http://jackwhiteiii.com/', 'https://www.youtube.com/user/JackWhiteVEVO', false, false);
