INSERT INTO "Event" VALUES ('cmnw9xebt009awvhpxydx7zpz', 'All Together Now - Campervan / Caravan Ticket', 'CONCERT', 'All Together Now', 'Curraghmore House', 'Portlaw', 'IE', '2026-07-31 00:00:00', '2026-08-02 00:00:00', 'https://www.ticketmaster.ie/all-together-now-campervan-caravan-ticket-portlaw-31-07-2026/event/180062FE90F81E2F', NULL, 'Each adult travelling must also have a full weekend camping ticket. Only proper purpose-built or adapted live-in vehicles will be permitted. There is no re-admittance from the Campervan Field. Once you are in your pitch, please do not move until you are ready to leave the festival on Monday.', 'https://s1.ticketm.net/dam/a/4be/a2eb3064-4e11-4418-8b29-b772511dc4be_RETINA_LANDSCAPE_16_9.jpg', NULL, 'TICKETMASTER', '17kZvxG62B8Xoyj', 'tm-all-together-now-curraghmore-house-portlaw-2026-07-31', 52.290224, 7.35937, true, '2026-04-12 21:26:36.233', '2026-04-12 21:26:36.238', NULL, NULL, NULL, NULL, NULL, false, 'https://www.facebook.com/ATNFestival/', 'https://www.instagram.com/alltogethernow.ie/', NULL, NULL, NULL, 'https://www.alltogethernow.ie/', 'https://www.youtube.com/channel/UC_04-lD4FqzVvzSKijR9D3g', false, false);
